pub fn PlaySongX(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.set_y(cpu.reg.a);
                cpu.set_a(cpu.mem[sym::soundon]);
                cpu.set_a(cpu.reg.a & cpu.mem[sym::musicon]);
                if cpu.reg.a != 0x00 {
                    pc = 2;
                } else {
                    pc = 1;
                }
            }
            1 => {
                cpu.set_a(cpu.reg.x);
                play(cpu);
                return;
            }
            2 => {
                cpu.set_a(cpu.reg.y);
                pc = 3;
            }
            3 => {
                crate::grafix::MINIT(cpu);
                swpage(cpu);
                pc = 4;
            }
            4 => {
                cpu.set_a(0x01);
                crate::ext::strobe(cpu);
                cpu.set_a(cpu.mem[0xc061]);
                cpu.set_a(cpu.reg.a | cpu.mem[0xc062]);
                cpu.set_a(cpu.reg.a | cpu.mem[sym::keypress]);
                if (cpu.reg.a as i8) < 0 {
                    pc = 6;
                } else {
                    pc = 5;
                }
            }
            5 => {
                pburn(cpu);
                pstars(cpu);
                pflow(cpu);
                crate::grafix::MPLAY(cpu);
                let _o: u8 = 0x00;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != 0x00 {
                    pc = 4;
                } else {
                    pc = 6;
                }
            }
            6 => {
                swpage(cpu);
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn PlaySong(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                crate::grafix::MINIT(cpu);
                swpage(cpu);
                pc = 1;
            }
            1 => {
                cpu.set_a(0x01);
                crate::ext::strobe(cpu);
                cpu.set_a(cpu.mem[0xc061]);
                cpu.set_a(cpu.reg.a | cpu.mem[0xc062]);
                cpu.set_a(cpu.reg.a | cpu.mem[sym::keypress]);
                if (cpu.reg.a as i8) < 0 {
                    pc = 3;
                } else {
                    pc = 2;
                }
            }
            2 => {
                pburn(cpu);
                pstars(cpu);
                pflow(cpu);
                crate::grafix::MPLAY(cpu);
                let _o: u8 = 0x00;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != 0x00 {
                    pc = 1;
                } else {
                    pc = 3;
                }
            }
            3 => {
                swpage(cpu);
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn PlaySongI(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.set_y(cpu.reg.a);
                cpu.set_a(cpu.mem[sym::soundon]);
                cpu.set_a(cpu.reg.a & cpu.mem[sym::musicon]);
                if cpu.reg.a != 0x00 {
                    pc = 3;
                } else {
                    pc = 1;
                }
            }
            1 => {
                cpu.set_a(cpu.reg.x);
                if cpu.reg.a == 0x00 {
                    pc = 8;
                } else {
                    pc = 2;
                }
            }
            2 => {
                play(cpu);
                return;
            }
            3 => {
                cpu.set_a(cpu.reg.y);
                crate::grafix::MINIT(cpu);
                swpage(cpu);
                pc = 4;
            }
            4 => {
                crate::grafix::MUSICKEYS(cpu);
                let _o: u8 = 0x80;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a >= 0x80 {
                    pc = 7;
                } else {
                    pc = 5;
                }
            }
            5 => {
                pburn(cpu);
                pstars(cpu);
                pflow(cpu);
                crate::grafix::MPLAY(cpu);
                let _o: u8 = 0x00;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != 0x00 {
                    pc = 4;
                } else {
                    pc = 6;
                }
            }
            6 => {
                swpage(cpu);
                return;
            }
            7 => {
                crate::grafix::DOSTARTGAME(cpu);
                return;
            }
            8 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn swpage(cpu: &mut Cpu) {
    cpu.set_a(cpu.mem[sym::PAGE]);
    cpu.set_a(cpu.reg.a ^ 0x20);
    cpu.mem[sym::PAGE] = cpu.reg.a;
    return;
}

pub fn flashon(cpu: &mut Cpu) {
    cpu.set_a(cpu.mem[sym::lightning]);
    if cpu.reg.a == 0x00 {
        return;
    }
    cpu.set_a(cpu.mem[sym::lightcolor]);
    DOFLASHON(cpu);
    return;
}

pub fn flashoff(cpu: &mut Cpu) {
    cpu.set_a(cpu.mem[sym::lightning]);
    if cpu.reg.a == 0x00 {
        return;
    }
    let _v = cpu.mem[sym::lightning].wrapping_sub(1);
    cpu.mem[sym::lightning] = _v;
    cpu.set_nz(_v);
    DOFLASHOFF(cpu);
    return;
}

pub fn play(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.mem[sym::SceneCount] = cpu.reg.a;
                pc = 1;
            }
            1 => {
                crate::grafix::RND(cpu);
                cpu.set_a(cpu.mem[sym::SPEED]);
                PAUSE(cpu);
                crate::ext::strobe(cpu);
                cpu.set_a(cpu.mem[sym::level]);
                if cpu.reg.a != 0x00 {
                    pc = 4;
                } else {
                    pc = 2;
                }
            }
            2 => {
                crate::specialk::DEMOKEYS(cpu);
                if !cpu.flags.n {
                    pc = 5;
                } else {
                    pc = 3;
                }
            }
            3 => {
                cpu.set_a(0x01);
                crate::grafix::DOSTARTGAME(cpu);
                return;
            }
            4 => {
                cpu.set_a(cpu.mem[0xc061]);
                cpu.set_a(cpu.reg.a | cpu.mem[0xc062]);
                cpu.set_a(cpu.reg.a | cpu.mem[sym::keypress]);
                if (cpu.reg.a as i8) < 0 {
                    pc = 9;
                } else {
                    pc = 5;
                }
            }
            5 => {
                NextFrame(cpu);
                flashon(cpu);
                FrameAdv(cpu);
                flashoff(cpu);
                cpu.set_a(cpu.mem[sym::soundon]);
                if cpu.reg.a == 0x00 {
                    pc = 7;
                } else {
                    pc = 6;
                }
            }
            6 => {
                crate::sound::PLAYBACK(cpu);
                crate::specialk::ZEROSOUND(cpu);
                pc = 7;
            }
            7 => {
                let _v = cpu.mem[sym::SceneCount].wrapping_sub(1);
                cpu.mem[sym::SceneCount] = _v;
                cpu.set_nz(_v);
                if !cpu.flags.z {
                    pc = 1;
                } else {
                    pc = 8;
                }
            }
            8 => {
                return;
            }
            9 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn playloop(cpu: &mut Cpu) {
    crate::grafix::RND(cpu);
    cpu.set_a(cpu.mem[sym::SPEED]);
    PAUSE(cpu);
    crate::ext::strobe(cpu);
    cpu.set_a(cpu.mem[sym::level]);
    if cpu.reg.a != 0x00 {
        cpu.set_a(cpu.mem[0xc061]);
        cpu.set_a(cpu.reg.a | cpu.mem[0xc062]);
        cpu.set_a(cpu.reg.a | cpu.mem[sym::keypress]);
        if (cpu.reg.a as i8) < 0 {
            return;
        }
    } else {
        crate::specialk::DEMOKEYS(cpu);
        if cpu.flags.n {
            cpu.set_a(0x01);
            crate::grafix::DOSTARTGAME(cpu);
            return;
        }
    }
    NextFrame(cpu);
    flashon(cpu);
    FrameAdv(cpu);
    flashoff(cpu);
    cpu.set_a(cpu.mem[sym::soundon]);
    if cpu.reg.a != 0x00 {
        crate::sound::PLAYBACK(cpu);
        crate::specialk::ZEROSOUND(cpu);
    }
    let _v = cpu.mem[sym::SceneCount].wrapping_sub(1);
    cpu.mem[sym::SceneCount] = _v;
    cpu.set_nz(_v);
    if !cpu.flags.z {
        playloop(cpu);
        return;
    }
    return;
}

