    cpu.mem[sym::lastpotion] = cpu.reg.a;
    cpu.set_x(0x01);
    cpu.mem[sym::clrbtn] = cpu.reg.x;
    cpu.mem[((cpu.mem[sym::BlueType] as usize | (cpu.mem[sym::BlueType + 1] as usize) << 8) + cpu.reg.y as usize) & 0xffff] = 0x01;
